export function MenuScreen() {
  const appState = useAppStore(state => state.appState);
  const updateUserName = useAppStore(state => state.updateUserName);
  const resetApp = useAppStore(state => state.resetApp);
  const [userName, setUserName] = useState(appState?.user.name ?? '');

  if (!appState) {
    return null;
  }

  const completedSpend = appState.vault.carts
    .filter(cart => cart.status === 'completed')
    .reduce((sum, cart) => sum + computeCartTotal(appState.vault, cart), 0);

  const shareSnapshot = async () => {
    await Share.open({
      title: 'Grock summary',
      message: `Grock vault: ${appState.vault.categories.length} categories, ${appState.vault.carts.length} carts, completed spend ${formatCurrency(completedSpend)}.`,
    });
  };

  return (
    <ScrollView style={styles.screen} contentContainerStyle={styles.content}>
      <Text style={styles.title}>Menu</Text>
      <Text style={styles.subtitle}>Account, reset, and support surfaces for the RN migration.</Text>

      <View style={styles.card}>
        <Text style={styles.cardTitle}>Your name</Text>
        <TextInput
          style={styles.input}
          value={userName}
          onChangeText={setUserName}
          placeholder="Your name"
          placeholderTextColor={colors.mutedInk}
        />
        <Pressable
          style={styles.primaryButton}
          onPress={() => {
            updateUserName(userName).catch(() => undefined);
          }}
        >
          <Text style={styles.primaryButtonText}>Save name</Text>
        </Pressable>
      </View>

      <View style={styles.card}>
        <Text style={styles.cardTitle}>Subscription state</Text>
        <Text style={styles.cardCopy}>Pro active: {appState.preferences.isPro ? 'Yes' : 'No'}</Text>
        <Text style={styles.cardCopy}>
          Free editable stores: {appState.preferences.freeEditableStoreKeys.length}
        </Text>
      </View>

      <View style={styles.card}>
        <Text style={styles.cardTitle}>Share summary</Text>
        <Text style={styles.cardCopy}>Open the native share sheet with the current vault snapshot.</Text>
        <Pressable
          style={styles.primaryButton}
          onPress={() => {
            shareSnapshot().catch(() => undefined);
          }}
        >
          <Text style={styles.primaryButtonText}>Share</Text>
        </Pressable>
      </View>

      <View style={styles.card}>
        <Text style={styles.cardTitle}>Danger zone</Text>
        <Text style={styles.cardCopy}>Reset the RN app state back to an empty first-launch vault.</Text>
        <Pressable
          style={[styles.primaryButton, styles.dangerButton]}
          onPress={() =>
            Alert.alert('Reset Grock RN state', 'This clears the new SQLite/MMKV app state.', [
              { text: 'Cancel', style: 'cancel' },
              {
                text: 'Reset',
                style: 'destructive',
                onPress: () => {
                  resetApp().catch(() => undefined);
                },
              },
            ])
          }
        >
          <Text style={styles.primaryButtonText}>Reset local state</Text>
        </Pressable>
      </View>
    </ScrollView>
  );
}

