  track: {
    height: 8,
    borderRadius: 4,
    backgroundColor: colors.line,
    overflow: 'hidden',
  },
  fill: {
    height: 8,
    borderRadius: 4,
  },
  over: {
    ...typography.caption,
    color: colors.danger,
    fontWeight: '700',
  },
});

