import { StyleSheet, Text, View } from 'react-native';

import { formatCurrency } from '../../../lib/format';
import { colors } from '../../../theme/colors';

interface PlannedVsActualPillProps {
  planned: number;
  actual: number;
}

export function PlannedVsActualPill({ planned, actual }: PlannedVsActualPillProps) {
  const diff = actual - planned;
  if (diff === 0) return null;

  const isMore = diff > 0;

  return (
    <View style={[styles.pill, isMore ? styles.pillOver : styles.pillUnder]}>
      <Text style={[styles.text, isMore ? styles.textOver : styles.textUnder]}>
        {isMore ? '+' : ''}{formatCurrency(diff)} vs plan
      </Text>
    </View>
  );
}

