333→export function computeDashboardSummary(state: VaultAppState): DashboardSummary {
334→  const activeCarts = state.vault.carts.filter(cart => !cart.isDeleted && cart.status !== 'completed');
335→  const completedCarts = state.vault.carts.filter(cart => !cart.isDeleted && cart.status === 'completed');
336→  const cartTotals = completedCarts.map(cart => ({ cart, total: computeCartTotal(state.vault, cart) }));
337→  const totalSpent = cartTotals.reduce((sum, entry) => sum + entry.total, 0);
338→  const overBudgetCount = cartTotals.filter(entry => entry.total > entry.cart.budget).length;
339→  const itemCount = state.vault.categories.reduce((sum, category) => sum + category.items.length, 0);
340→
341→  return {
342→    activeCarts,
343→    completedCarts,
344→    totalSpent,
345→    overBudgetCount,
346→    itemCount,
347→  };
348→}
