350→export function completeOnboardingState(
351→  baseState: VaultAppState,
352→  input: CompleteOnboardingInput
353→): VaultAppState {
354→  const state = baseState;
355→  const normalizedName = input.userName.trim();
356→  const normalizedStore = input.primaryStore.trim();
357→  const normalizedItemName = input.firstItemName.trim();
358→  const normalizedUnit = input.firstItemUnit.trim();
359→  const category = getCategoryById(state.vault, input.firstCategoryId);
360→
361→  if (!category) {
362→    throw new Error('Selected category was not found.');
363→  }
364→
365→  state.user.name = normalizedName;
366→  state.preferences.userName = normalizedName;
367→  state.preferences.hasCompletedOnboarding = true;
368→
369→  const existingStore = state.vault.stores.find(store => store.name.toLowerCase() === normalizedStore.toLowerCase());
370→  const store = existingStore ?? {
371→    id: createId('store'),
372→    name: normalizedStore,
373→    createdAt: new Date().toISOString(),
374→  };
375→
376→  if (!existingStore) {
377→    state.vault.stores.push(store);
378→  }
379→
380→  category.items.unshift({
381→    id: createId('item'),
382→    name: normalizedItemName,
383→    categoryId: category.uid,
384→    priceOptions: [
385→      {
386→        id: createId('priceOption'),
387→        store: store.name,
