 30→async function refreshSubscription(
 31→  set: (partial: Partial<AppStoreState>) => void,
 32→  current: SubscriptionSnapshot
 33→): Promise<SubscriptionSnapshot> {
 34→  const loading = { ...current, isLoading: true };
 35→  set({ subscription: loading });
 36→  const next = await subscriptionService.refresh(loading);
 37→  set({ subscription: next });
 38→  return next;
 39→}
