 15→import { CartSummaryBar } from './components/CartSummaryBar';
 16→import { StoreGroupToggle } from './components/StoreGroupToggle';
 17→
 18→type Props = RootStackScreenProps<'CartDetail'>;
 19→
 20→export function CartDetailScreen({ route }: Props) {
 21→  const appState = useAppStore(state => state.appState);
 22→  const toggleCartItemFulfillment = useAppStore(state => state.toggleCartItemFulfillment);
 23→  const advanceCartStatus = useAppStore(state => state.advanceCartStatus);
 24→  const [groupByStore, setGroupByStore] = useState(false);
 25→
 26→  const cart = useMemo(
 27→    () => appState?.vault.carts.find(entry => entry.id === route.params.cartId),
 28→    [appState, route.params.cartId]
 29→  );
 30→
 31→  const total = useMemo(
 32→    () => (appState && cart ? computeCartTotal(appState.vault, cart) : 0),
 33→    [appState, cart]
 34→  );
 35→
 36→  const sortedItems = useMemo(() => {
 37→    if (!cart) return [];
 38→    const items = [...cart.cartItems];
 39→    if (groupByStore) {
 40→      items.sort((a, b) => {
 41→        const storeA = a.actualStore ?? a.plannedStore;
 42→        const storeB = b.actualStore ?? b.plannedStore;
 43→        return storeA.localeCompare(storeB);
 44→      });
 45→    }
 46→    // Show unfulfilled first
 47→    items.sort((a, b) => Number(a.isFulfilled) - Number(b.isFulfilled));
 48→    return items;
 49→  }, [cart, groupByStore]);
 50→
 51→  const fulfilledCount = useMemo(
 52→    () => (cart ? cart.cartItems.filter(i => i.isFulfilled).length : 0),
 53→    [cart]
 54→  );
 55→
 56→  const handleFulfill = useCallback(
 57→    (cartItemId: string) => {
 58→      if (!cart) return;
 59→      toggleCartItemFulfillment(cart.id, cartItemId).catch(() => undefined);
 60→    },
 61→    [cart, toggleCartItemFulfillment]
 62→  );
 63→
 64→  const renderItem = useCallback(
 65→    ({ item }: { item: CartItem }) => (
 66→      <CartItemRow
 67→        item={item}
 68→        isShopping={cart?.status === 'shopping'}
 69→        onFulfill={() => handleFulfill(item.id)}
 70→      />
 71→    ),
 72→    [cart?.status, handleFulfill]
 73→  );
 74→
 75→  if (!appState || !cart) return null;
 76→
 77→  const isShopping = cart.status === 'shopping';
 78→  const isCompleted = cart.status === 'completed';
 79→
 80→  return (
 81→    <GestureHandlerRootView style={styles.screen}>
 82→      <FlatList
 83→        data={sortedItems}
 84→        keyExtractor={item => item.id}
 85→        renderItem={renderItem}
 86→        style={styles.screen}
 87→        contentContainerStyle={styles.content}
 88→        ListHeaderComponent={
 89→          <View style={styles.header}>
 90→            <CartHero cart={cart} />
 91→            <BudgetBar spent={total} budget={cart.budget} />
 92→            {!isCompleted && (
 93→              <View style={styles.controls}>
 94→                <StoreGroupToggle
 95→                  grouped={groupByStore}
 96→                  onToggle={() => setGroupByStore(prev => !prev)}
 97→                />
 98→              </View>
 99→            )}
100→            <CartStatusButton
101→              status={cart.status}
102→              onPress={() => { advanceCartStatus(cart.id).catch(() => undefined); }}
103→            />
104→          </View>
105→        }
106→        ListEmptyComponent={
107→          <EmptyState title="No items" message="This cart has no items yet." />
108→        }
109→        initialNumToRender={10}
110→        maxToRenderPerBatch={5}
111→        windowSize={5}
112→        ItemSeparatorComponent={ItemSeparator}
113→      />
114→
115→      {(isShopping || isCompleted) && (
116→        <CartSummaryBar
117→          fulfilledCount={fulfilledCount}
118→          totalCount={cart.cartItems.length}
119→          runningTotal={total}
120→        />
121→      )}
122→    </GestureHandlerRootView>
123→  );
124→}
